solutions.python:
class Solution:
    def checkRecord(self, s):
        absent = 0
        late = 0
        for ch in s:
            if ch == 'A':
                absent += 1
                if absent >= 2:
                    return False
            if ch == 'L':
                late += 1
                if late >= 3:
                    return False
            else:
                late = 0
        return True

