var checkRecord = function(s) {
    let absent = 0, late = 0;
    for (const ch of s) {
        if (ch === 'A') {
            absent++;
            if (absent >= 2) return false;
        }
        if (ch === 'L') {
            late++;
            if (late >= 3) return false;
        } else {
            late = 0;
        }
    }
    return true;
};
